#include "primer/hyperloglog.h"
#include <cmath>

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  if (n_bits_ <= 0) {
    n_bits_ = 0;
    registers_.resize(1, 0);
  } else {
    registers_.resize(1ULL << n_bits_, 0);
  }
}

/**
 * @brief Function that computes binary.
 *
 * @param[in] hash
 * @returns binary of a given hash
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

/**
 * @brief Function that computes leading zeros.
 *
 * @param[in] bset - binary values of a given bitset
 * @returns position of leftmost 1 in given binary set (1-indexed from the right, after the bucket bits)
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // We look for the position of the leftmost 1 in the portion after the bucket bits
  // The remaining bits start from position (BITSET_CAPACITY - 1 - n_bits_) down to 0
  // Position is counted from right to left (1-indexed)

  // Starting from the most significant bit (after bucket bits) going down
  for (int i = BITSET_CAPACITY - 1 - n_bits_; i >= 0; i--) {
    if (bset.test(i)) {
      // Position from the leftmost bit of the remaining portion (1-indexed)
      return static_cast<uint64_t>(BITSET_CAPACITY - n_bits_ - i);
    }
  }
  // If all bits are 0, return the maximum position + 1
  return static_cast<uint64_t>(BITSET_CAPACITY - n_bits_ + 1);
}

/**
 * @brief Adds a value into the HyperLogLog.
 *
 * @param[in] val - value that's added into hyperloglog
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ < 0) {
    return;
  }

  hash_t hash = CalculateHash(val);
  std::bitset<BITSET_CAPACITY> binary = ComputeBinary(hash);

  // Extract the bucket index from the n_bits_ most significant bits
  uint64_t bucket_index = 0;
  if (n_bits_ > 0) {
    for (int i = 0; i < n_bits_; i++) {
      if (binary.test(BITSET_CAPACITY - 1 - i)) {
        bucket_index |= (1ULL << (n_bits_ - 1 - i));
      }
    }
  }

  // Find position of leftmost 1 in the remaining bits
  uint64_t pos = PositionOfLeftmostOne(binary);

  // Update the register with the maximum value
  std::lock_guard<std::mutex> lock(mutex_);
  if (pos > registers_[bucket_index]) {
    registers_[bucket_index] = pos;
  }
}

/**
 * @brief Function that computes cardinality.
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ < 0) {
    cardinality_ = 0;
    return;
  }

  size_t m = registers_.size();  // Number of registers (2^n_bits)

  // Compute the harmonic mean
  double sum = 0.0;
  for (size_t i = 0; i < m; i++) {
    sum += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  // Apply the HyperLogLog formula: E = alpha * m^2 / sum
  double alpha = CONSTANT;
  double estimate = alpha * static_cast<double>(m) * static_cast<double>(m) / sum;

  cardinality_ = static_cast<size_t>(estimate);
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub

