#include "primer/hyperloglog_presto.h"
#include <cmath>

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : cardinality_(0), n_leading_bits_(n_leading_bits) {
  if (n_leading_bits_ <= 0) {
    n_leading_bits_ = 0;
    dense_bucket_.resize(1, std::bitset<DENSE_BUCKET_SIZE>(0));
  } else {
    dense_bucket_.resize(1ULL << n_leading_bits_, std::bitset<DENSE_BUCKET_SIZE>(0));
  }
}

/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ < 0) {
    return;
  }

  hash_t hash = CalculateHash(val);

  // Extract bucket index from the n_leading_bits_ most significant bits
  uint64_t bucket_index = 0;
  if (n_leading_bits_ > 0) {
    bucket_index = hash >> (64 - n_leading_bits_);
  }

  // Calculate the number of trailing zeros (position of first 1 from right)
  // This is the "rho" value in HyperLogLog Presto
  int remaining_bits = 64 - n_leading_bits_;

  // Mask to only consider the remaining bits after the bucket index bits
  uint64_t remaining_hash = hash;
  if (n_leading_bits_ > 0) {
    // Clear the leading bits used for bucket index
    remaining_hash = hash & ((1ULL << (64 - n_leading_bits_)) - 1);
  }

  uint64_t pos = 0;

  if (remaining_hash == 0) {
    // If all remaining bits are 0, position is the number of remaining bits
    pos = static_cast<uint64_t>(remaining_bits);
  } else {
    // Count trailing zeros
    for (int i = 0; i < remaining_bits; i++) {
      if ((remaining_hash >> i) & 1ULL) {
        pos = static_cast<uint64_t>(i);
        break;
      }
    }
  }

  // Split the value into dense (lower 4 bits) and overflow (upper 3 bits)
  uint64_t current_dense = dense_bucket_[bucket_index].to_ullong();
  uint64_t current_overflow = 0;

  if (overflow_bucket_.find(static_cast<uint16_t>(bucket_index)) != overflow_bucket_.end()) {
    current_overflow = overflow_bucket_[static_cast<uint16_t>(bucket_index)].to_ullong();
  }

  // Reconstruct current value from dense and overflow
  uint64_t current_value = (current_overflow << DENSE_BUCKET_SIZE) | current_dense;

  // Update if new value is larger
  if (pos > current_value) {
    // Split pos into dense (lower 4 bits) and overflow (upper 3 bits)
    uint64_t new_dense = pos & 0xF;  // Lower 4 bits
    uint64_t new_overflow = (pos >> 4) & 0x7;  // Upper 3 bits

    dense_bucket_[bucket_index] = std::bitset<DENSE_BUCKET_SIZE>(new_dense);
    if (new_overflow > 0) {
      overflow_bucket_[static_cast<uint16_t>(bucket_index)] = std::bitset<OVERFLOW_BUCKET_SIZE>(new_overflow);
    } else {
      overflow_bucket_[static_cast<uint16_t>(bucket_index)] = std::bitset<OVERFLOW_BUCKET_SIZE>(0);
    }
  }
}

/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_leading_bits_ < 0) {
    cardinality_ = 0;
    return;
  }

  size_t m = dense_bucket_.size();  // Number of registers (2^n_leading_bits)

  // Compute the harmonic mean
  double sum = 0.0;
  for (size_t i = 0; i < m; i++) {
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = 0;
    if (overflow_bucket_.find(static_cast<uint16_t>(i)) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[static_cast<uint16_t>(i)].to_ullong();
    }
    uint64_t value = (overflow_val << DENSE_BUCKET_SIZE) | dense_val;
    sum += std::pow(2.0, -static_cast<double>(value));
  }

  // Apply the HyperLogLog formula: E = alpha * m^2 / sum
  double alpha = CONSTANT;
  double estimate = alpha * static_cast<double>(m) * static_cast<double>(m) / sum;

  cardinality_ = static_cast<uint64_t>(estimate);
}

template class HyperLogLogPresto<int64_t>;
template class HyperLogLogPresto<std::string>;
}  // namespace bustub

